func (v ItemsValue) ToObjectValue(ctx context.Context) (basetypes.ObjectValue, diag.Diagnostics) {
	var diags diag.Diagnostics

	var tagsVal basetypes.ListValue
	switch {
	case v.Tags.IsUnknown():
		tagsVal = types.ListUnknown(types.StringType)
	case v.Tags.IsNull():
		tagsVal = types.ListNull(types.StringType)
	default:
		var d diag.Diagnostics
		tagsVal, d = types.ListValue(types.StringType, v.Tags.Elements())
		diags.Append(d...)
	}

	if diags.HasError() {
		return types.ObjectUnknown(map[string]attr.Type{
			"_id":          basetypes.StringType{},
			"activity":     basetypes.StringType{},
			"group":        basetypes.StringType{},
			"group_type":   basetypes.StringType{},
			"metadata":     jsontypes.NormalizedType{},
			"service_type": basetypes.StringType{},
			"tags": basetypes.ListType{
				ElemType: types.StringType,
			},
			"timestamp": basetypes.StringType{},
		}), diags
	}

	attributeTypes := map[string]attr.Type{
		"_id":          basetypes.StringType{},
		"activity":     basetypes.StringType{},
		"group":        basetypes.StringType{},
		"group_type":   basetypes.StringType{},
		"metadata":     jsontypes.NormalizedType{},
		"service_type": basetypes.StringType{},
		"tags": basetypes.ListType{
			ElemType: types.StringType,
		},
		"timestamp": basetypes.StringType{},
	}

	if v.IsNull() {
		return types.ObjectNull(attributeTypes), diags
	}

	if v.IsUnknown() {
		return types.ObjectUnknown(attributeTypes), diags
	}

	objVal, diags := types.ObjectValue(
		attributeTypes,
		map[string]attr.Value{
			"_id":          v.UnderscoreId,
			"activity":     v.Activity,
			"group":        v.Group,
			"group_type":   v.GroupType,
			"metadata":     v.Metadata,
			"service_type": v.ServiceType,
			"tags":         tagsVal,
			"timestamp":    v.Timestamp,
		})

	return objVal, diags
}

func (v ItemsValue) Equal(o attr.Value) bool {
	other, ok := o.(ItemsValue)

	if !ok {
		return false
	}

	if v.state != other.state {
		return false
	}

	if v.state != attr.ValueStateKnown {
		return true
	}

	if !v.UnderscoreId.Equal(other.UnderscoreId) {
		return false
	}

	if !v.Activity.Equal(other.Activity) {
		return false
	}

	if !v.Group.Equal(other.Group) {
		return false
	}

	if !v.GroupType.Equal(other.GroupType) {
		return false
	}

	if !v.Metadata.Equal(other.Metadata) {
		return false
	}

	if !v.ServiceType.Equal(other.ServiceType) {
		return false
	}

	if !v.Tags.Equal(other.Tags) {
		return false
	}

	if !v.Timestamp.Equal(other.Timestamp) {
		return false
	}

	return true
}

